import base64
import os
import pathlib
import subprocess
import sys

GOLDEN_SCRIPT_B64 = ""
cmd = [sys.executable, "-c", base64.b64decode(GOLDEN_SCRIPT_B64).decode("utf-8")]
env = os.environ.copy()
root = str(pathlib.Path.cwd())
env["PYTHONPATH"] = root + (os.pathsep + env["PYTHONPATH"] if env.get("PYTHONPATH") else "")
proc = subprocess.run(cmd, text=True, capture_output=True, timeout=300, env=env)
print(proc.stdout, end="")
print(proc.stderr, end="")
raise SystemExit(proc.returncode)
